import "./App.css";
import "./nav.css";
import Slider from "./Slider";
import Nav from "./nav";
import Tooler from "./tooler";
import MyProjects from "./myProjects";
import Footer from "./Footer";

function App() {
  return (
    <div className="App">
      <div className="pushMenu"></div>
      <div className="header">
        <Nav />
        <h3 className="Radicc">RADICC</h3>
      </div>
      <div className="body">
        <h1 className="tomRadText">A frontend developer</h1>
        <h3 className="tomRadUnderText">
          I am Tomas Radic a selfthouhgt frontend developer trying to change
          profession.
        </h3>
        <Slider />
      </div>
      <Tooler />
      <MyProjects />
      <Footer />
    </div>
  );
}
export default App;
